const DEFAULT_TEXT_FILE_ENCODING = 'auto';
const TEXT_FILE_ENCODING_OPTIONS = new Set(['auto', 'utf8', 'windows-1252', 'windows-1251', 'gbk', 'big5', 'shift_jis', 'euc-kr']);

function normalizeTextFileEncoding(value) {
  const raw = String(value || DEFAULT_TEXT_FILE_ENCODING).trim().toLowerCase();
  const aliases = {
    auto: 'auto',
    utf8: 'utf8',
    'utf-8': 'utf8',
    'windows-1252': 'windows-1252',
    cp1252: 'windows-1252',
    'windows-1251': 'windows-1251',
    cp1251: 'windows-1251',
    gbk: 'gbk',
    cp936: 'gbk',
    big5: 'big5',
    cp950: 'big5',
    shift_jis: 'shift_jis',
    'shift-jis': 'shift_jis',
    sjis: 'shift_jis',
    cp932: 'shift_jis',
    'euc-kr': 'euc-kr',
    euc_kr: 'euc-kr',
    cp949: 'euc-kr'
  };
  const normalized = aliases[raw] || DEFAULT_TEXT_FILE_ENCODING;
  return TEXT_FILE_ENCODING_OPTIONS.has(normalized) ? normalized : DEFAULT_TEXT_FILE_ENCODING;
}

