function isReadonlyRuleField(tabKey, field) {
  const base = normalizeRuleLookupKey(field && (field.baseKey || field.key));
  return (tabKey === 'improvements' || tabKey === 'technologies' || tabKey === 'civilizations' || tabKey === 'governments' || tabKey === 'units' || tabKey === 'resources') && base === 'civilopediaentry';
}

function isReadonlyBiqStructureField(sectionCode, field) {
  const code = String(sectionCode || '').toUpperCase();
  const base = normalizeRuleLookupKey(field && (field.baseKey || field.key));
  return (code === 'TERR' && (base === 'civilopediaentry' || base === 'landmarkcivilopediaentry'))
    || (code === 'TFRM' && base === 'civilopediaentry');
}

function renderTerrainValuesTable(groupCard, groupFields, tab) {
  const pairDefs = [
    ['food', 'landmarkfood', 'Food'],
    ['shields', 'landmarkshields', 'Shields'],
    ['commerce', 'landmarkcommerce', 'Commerce'],
    ['foodbonus', 'landmarkfoodbonus', 'Irrigation Bonus'],
    ['shieldsbonus', 'landmarkshieldsbonus', 'Mining Bonus'],
    ['commercebonus', 'landmarkcommercebonus', 'Trade Bonus'],
    ['movementcost', 'landmarkmovementcost', 'Movement Cost'],
    ['defencebonus', 'landmarkdefencebonus', 'Defence Bonus']
  ];
  const editable = !tab.readOnly;
  const byKey = new Map(groupFields.map((field) => [normalizeRuleLookupKey(field && (field.baseKey || field.key)), field]));
  const tableRow = document.createElement('div');
  tableRow.className = 'rule-row';
  const label = document.createElement('label');
  label.className = 'field-meta';
  label.textContent = 'Terrain Values';
  tableRow.appendChild(label);

  const controlWrap = document.createElement('div');
  controlWrap.className = 'rule-control';
  const table = document.createElement('table');
  table.className = 'time-progression-table';
  table.style.tableLayout = 'fixed';
  const thead = document.createElement('thead');
  const headRow = document.createElement('tr');
  ['', 'Regular Terrain', 'Landmark Terrain'].forEach((title) => {
    const th = document.createElement('th');
    th.textContent = title;
    headRow.appendChild(th);
  });
  thead.appendChild(headRow);
  table.appendChild(thead);
  const tbody = document.createElement('tbody');

  const makeNumberCell = (field) => {
    const td = document.createElement('td');
    if (!field) {
      td.textContent = '(n/a)';
      return td;
    }
    const spec = getBiqStructureFieldSpec('TERR', field) || {};
    if (editable) {
      const input = document.createElement('input');
      input.type = 'number';
      if (Number.isFinite(spec.min)) input.min = String(spec.min);
      if (Number.isFinite(spec.max)) input.max = String(spec.max);
      input.value = String(parseIntFromDisplayValue(field.value) ?? '');
      wireGroupedUndoSession(input, {
        key: `BIQ_TERRAIN_VALUES:${String(field.baseKey || field.key || '')}`,
        getValue: () => input.value
      });
      input.addEventListener('input', () => {
        field.value = input.value;
        setDirty(true);
      });
      td.appendChild(input);
      return td;
    }
    td.textContent = String(field.value || '0');
    return td;
  };

  pairDefs.forEach(([regularKey, landmarkKey, rowLabel]) => {
    const tr = document.createElement('tr');
    const rowHead = document.createElement('td');
    rowHead.textContent = rowLabel;
    tr.appendChild(rowHead);
    tr.appendChild(makeNumberCell(byKey.get(regularKey)));
    tr.appendChild(makeNumberCell(byKey.get(landmarkKey)));
    tbody.appendChild(tr);
  });
  table.appendChild(tbody);
  controlWrap.appendChild(table);
  tableRow.appendChild(controlWrap);
  groupCard.appendChild(tableRow);

  return pairDefs.flatMap(([regularKey, landmarkKey]) => [byKey.get(regularKey), byKey.get(landmarkKey)]).filter(Boolean);
}

function renderRuleCitySizeLimitsTable(groupCard, groupFields, entry, referenceEditable, options = {}) {
  const byKey = new Map(groupFields.map((field) => [normalizeRuleLookupKey(field && (field.baseKey || field.key)), field]));
  const showInlineLabel = options.showInlineLabel !== false;
  const tableRow = document.createElement('div');
  tableRow.className = 'rule-row';
  if (showInlineLabel) {
    const label = document.createElement('label');
    label.className = 'field-meta';
    label.textContent = 'City Size Limits';
    tableRow.appendChild(label);
  } else {
    const spacer = document.createElement('div');
    spacer.className = 'field-meta';
    spacer.setAttribute('aria-hidden', 'true');
    tableRow.appendChild(spacer);
  }

  const controlWrap = document.createElement('div');
  controlWrap.className = 'rule-control';
  const panel = document.createElement('div');
  panel.className = 'rule-city-size-panel';
  const grid = document.createElement('div');
  grid.className = 'rule-city-size-grid';

  ['', 'Name', 'Maximum Size'].forEach((title, index) => {
    const header = document.createElement('div');
    header.className = index === 0 ? 'rule-city-size-corner' : 'rule-city-size-header';
    header.textContent = title;
    grid.appendChild(header);
  });

  const rows = [
    { level: 'Level One', nameKey: 'townname', sizeKey: 'maxcity1size' },
    { level: 'Level Two', nameKey: 'cityname', sizeKey: 'maxcity2size' },
    { level: 'Level Three', nameKey: 'metropolisname', sizeKey: null }
  ];
  const makeNameCell = (field, placeholder) => {
    const cell = document.createElement('div');
    cell.className = 'rule-city-size-cell';
    const spec = getBiqStructureFieldSpec('RULE', field) || {};
    if (!field) {
      cell.textContent = '(n/a)';
      return cell;
    }
    if (referenceEditable) {
      const input = document.createElement('input');
      input.type = 'text';
      input.className = 'rule-city-size-input';
      input.value = String(field.value || '');
      input.placeholder = placeholder || '';
      wireGroupedUndoSession(input, {
        key: `CITY_SIZE_NAME:${normalizeRuleLookupKey(field && (field.baseKey || field.key))}`,
        getValue: () => input.value
      });
      input.addEventListener('input', () => {
        field.value = String(input.value || '');
        setDirty(true);
      });
      cell.appendChild(input);
      return cell;
    }
    cell.textContent = String(field.value || '');
    if (spec.label) cell.title = spec.label;
    return cell;
  };
  const makeSizeCell = (field) => {
    const cell = document.createElement('div');
    cell.className = 'rule-city-size-cell';
    if (!field) {
      cell.classList.add('rule-city-size-cell-empty');
      const none = document.createElement('span');
      none.className = 'hint';
      none.textContent = '—';
      cell.appendChild(none);
      return cell;
    }
    if (referenceEditable) {
      const input = document.createElement('input');
      input.type = 'number';
      input.className = 'rule-city-size-input';
      input.value = String(parseIntFromDisplayValue(field.value) ?? '');
      wireGroupedUndoSession(input, {
        key: `CITY_SIZE_VALUE:${normalizeRuleLookupKey(field && (field.baseKey || field.key))}`,
        getValue: () => input.value
      });
      input.addEventListener('input', () => {
        field.value = input.value;
        setDirty(true);
      });
      cell.appendChild(input);
      return cell;
    }
    cell.textContent = String(field.value || '0');
    return cell;
  };

  rows.forEach((rowDef) => {
    const rowHead = document.createElement('div');
    rowHead.className = 'rule-city-size-level';
    rowHead.textContent = `${rowDef.level}:`;
    grid.appendChild(rowHead);
    grid.appendChild(makeNameCell(byKey.get(rowDef.nameKey), rowDef.level));
    grid.appendChild(makeSizeCell(byKey.get(rowDef.sizeKey)));
  });
  panel.appendChild(grid);
  controlWrap.appendChild(panel);
  tableRow.appendChild(controlWrap);
  groupCard.appendChild(tableRow);

  return rows.flatMap((row) => [byKey.get(row.nameKey), byKey.get(row.sizeKey)]).filter(Boolean);
}

function getRuleFieldGroup(tabKey, field) {
  const spec = getRuleFieldSpec(tabKey, field);
  if (spec && spec.group) return spec.group;
  return 'Other';
}

function getRuleFieldOrder(tabKey, field) {
  const base = normalizeRuleLookupKey(field && (field.baseKey || field.key));
  const schema = REFERENCE_RULE_SCHEMAS[tabKey] || null;
  if (!schema || !Array.isArray(schema.order)) return Number.MAX_SAFE_INTEGER;
  const idx = schema.order.findIndex((item) => normalizeRuleLookupKey(item) === base);
  return idx >= 0 ? idx : Number.MAX_SAFE_INTEGER;
}

function getRuleFieldByBaseKey(fields, baseKey) {
  const target = normalizeRuleLookupKey(baseKey);
  return (Array.isArray(fields) ? fields : []).find((field) => normalizeRuleLookupKey(field && (field.baseKey || field.key)) === target) || null;
}

function appendRuleFieldsToGroupCard({ groupCard, fields, entry, tabKey, selectedBaseIndex, referenceEditable }) {
  (Array.isArray(fields) ? fields : []).forEach((field) => {
    const spec = getRuleFieldSpec(tabKey, field) || {};
    const row = document.createElement('div');
    row.className = 'rule-row';
    const label = document.createElement('label');
    label.className = 'field-meta';
    const displayLabel = getRuleFieldDisplayLabel(tabKey, field, spec);
    if (groupCard && groupCard.classList && groupCard.classList.contains('unit-prereq-compact-cell')) {
      const strong = document.createElement('strong');
      strong.textContent = displayLabel;
      label.appendChild(strong);
    } else {
      label.textContent = displayLabel;
    }
    const ruleFieldKey = String(field.baseKey || field.key || '');
    attachRichTooltip(
      label,
      withFieldHelp(
        `${formatSourceInfo(entry.sourceMeta && entry.sourceMeta.biq, 'BIQ')}\nField: ${ruleFieldKey}`,
        { tabKey, fieldKey: ruleFieldKey }
      )
    );
    row.appendChild(label);

    const controlWrap = document.createElement('div');
    controlWrap.className = 'rule-control';
    const enumOptions = getEnumOptionsForField(tabKey, field);
    const refOptions = getReferenceOptionsForField(tabKey, field);
    const desiredControl = spec.control || '';
    const baseKey = String(field.baseKey || field.key || '').toLowerCase();
    const useResourceTypeSegmented = tabKey === 'resources' && normalizeRuleLookupKey(baseKey) === 'type' && enumOptions.length > 0;
    const useColorSlotPicker = tabKey === 'civilizations' && (baseKey === 'defaultcolor' || baseKey === 'uniquecolor');
    const fieldEditable = referenceEditable && !isReadonlyRuleField(tabKey, field);

    if (fieldEditable) {
      const hasEnumOptions = enumOptions.length > 0;
      const hasRefOptions = refOptions.length > 0;
      const useReferencePicker = hasRefOptions && (desiredControl === 'reference' || (!desiredControl && !hasEnumOptions));

      if (useResourceTypeSegmented) {
        const parsedCurrent = parseIntFromDisplayValue(field.value);
        const current = enumOptions.find((opt) => String(opt.value) === String(parsedCurrent == null ? field.value : parsedCurrent));
        const segmented = makeSegmentedChoiceControl(
          enumOptions.map((opt) => String(opt.label || opt.value || '')),
          current ? String(current.label || current.value || '') : '',
          (nextLabel) => {
            const selected = enumOptions.find((opt) => String(opt.label || opt.value || '') === String(nextLabel || ''));
            if (!selected) return;
            rememberUndoSnapshot();
            field.value = String(selected.value);
            setDirty(true);
          }
        );
        controlWrap.appendChild(segmented);
      } else if (desiredControl === 'unit-list') {
        const initialValues = Array.isArray(field.multiValues)
          ? field.multiValues
          : String(field.value || '').split(',').map((v) => v.trim()).filter(Boolean);
        const editor = makeNamedListPickerEditor({
          tabKey: 'units',
          values: initialValues,
          onValuesChange: (values) => {
            rememberUndoSnapshot();
            setUnitListFieldValues(entry, String(field.baseKey || field.key || 'stealth_target'), values);
            setDirty(true);
            renderActiveTab({ preserveTabScroll: true });
          }
        });
        controlWrap.appendChild(editor);
      } else if (tabKey === 'units' && baseKey === 'iconindex') {
        const picker = createUnitIconIndexPicker(field.value, (value) => {
          rememberUndoSnapshot();
          field.value = String(value);
          if (entry && entry._pendingImportedUnitIcon) delete entry._pendingImportedUnitIcon;
          setDirty(true);
        }, entry);
        controlWrap.appendChild(picker);
        const iconWarnEl = document.createElement('div');
        iconWarnEl.className = 'unit-icon-field-warning hidden';
        controlWrap.appendChild(iconWarnEl);
        ensureCurrentUnits32AtlasMetrics().then((metrics) => {
          if (!iconWarnEl.isConnected) return;
          refreshPendingImportedUnitIconAssignments();
          if (hasPendingImportedUnitIconWarning(entry)) {
            iconWarnEl.textContent = 'Imported unit icon needs manual setup. Create or update this scenario\'s Art/Units/units_32.pcx, then choose the correct Icon Index.';
            iconWarnEl.classList.remove('hidden');
            return;
          }
          if (!metrics) return;
          const idx = getUnitIconValidationIndex(entry);
          if (!Number.isFinite(idx) || idx < 0) return;
          if (Math.floor(idx / metrics.cols) >= metrics.rows) {
            iconWarnEl.textContent = 'Icon index is out of range for the available units_32.pcx — this unit\'s icon will be missing at runtime.';
            iconWarnEl.classList.remove('hidden');
          }
        }).catch(() => {});
      } else if (useColorSlotPicker) {
        const colorPicker = createColorSlotPicker({
          currentValue: field.value,
          max: 31,
          onSelect: (value) => {
            rememberUndoSnapshot();
            field.value = String(value);
            setDirty(true);
          }
        });
        controlWrap.appendChild(colorPicker);
      } else if (useReferencePicker) {
        const labelText = String(field.label || field.key || 'value').trim();
        const isTechPrereqField = tabKey === 'technologies' && /^prerequisite/i.test(String(field.baseKey || field.key || ''));
        const normalizedCurrentValue = isTechPrereqField
          ? (() => {
              const idx = resolveTechIndexFromValue(field.value);
              return idx == null ? '-1' : String(idx);
            })()
          : field.value;
        const picker = createReferencePicker({
          options: refOptions,
          targetTabKey: (BIQ_FIELD_REFS[tabKey] || {})[normalizeRuleLookupKey(field && (field.baseKey || field.key))] || '',
          currentValue: normalizedCurrentValue,
          searchPlaceholder: `Search ${labelText}...`,
          noneLabel: '(none)',
          onSelect: (value) => {
            rememberUndoSnapshot();
            field.value = String(value);
            setDirty(true);
          }
        });
        controlWrap.appendChild(picker);
      } else if (desiredControl === 'range') {
        const wrap = document.createElement('div');
        wrap.style.display = 'flex';
        wrap.style.alignItems = 'center';
        wrap.style.gap = '8px';
        const range = document.createElement('input');
        range.type = 'range';
        const min = Number.isFinite(spec.min) ? Number(spec.min) : 0;
        const max = Number.isFinite(spec.max) ? Number(spec.max) : 100;
        range.min = String(min);
        range.max = String(max);
        const current = parseIntFromDisplayValue(field.value);
        range.value = String(current == null ? min : Math.max(min, Math.min(max, current)));
        wireGroupedUndoSession(range, {
          key: `RULE_FIELD:${tabKey}:${selectedBaseIndex}:${baseKey}`,
          getValue: () => range.value,
          commitOnChange: true
        });
        const valueText = document.createElement('span');
        valueText.className = 'field-meta';
        valueText.textContent = range.value;
        range.addEventListener('input', () => {
          valueText.textContent = range.value;
          field.value = String(range.value);
          setDirty(true);
        });
        wrap.appendChild(range);
        wrap.appendChild(valueText);
        controlWrap.appendChild(wrap);
      } else if (desiredControl === 'select' || desiredControl === 'reference' || hasEnumOptions || hasRefOptions) {
        const options = hasEnumOptions ? enumOptions : refOptions;
        const select = document.createElement('select');
        const hasNone = options.some((opt) => String(opt.value) === '-1');
        if (!hasNone) {
          const empty = document.createElement('option');
          empty.value = '-1';
          empty.textContent = '(none)';
          select.appendChild(empty);
        }
        options.forEach((opt) => {
          const o = document.createElement('option');
          o.value = String(opt.value);
          o.textContent = String(opt.label || `${opt.value}`);
          select.appendChild(o);
        });
        const isTechPrereqField = tabKey === 'technologies' && /^prerequisite/i.test(String(field.baseKey || field.key || ''));
        const parsed = isTechPrereqField ? resolveTechIndexFromValue(field.value) : parseIntFromDisplayValue(field.value);
        select.value = parsed == null ? '-1' : String(parsed);
        select.addEventListener('change', () => {
          rememberUndoSnapshot();
          const selectedOpt = options.find((opt) => String(opt.value) === String(select.value));
          field.value = selectedOpt ? String(selectedOpt.value) : '-1';
          setDirty(true);
        });
        controlWrap.appendChild(select);
      } else if (desiredControl === 'bool' || isLikelyBooleanField(field)) {
        const checkWrap = document.createElement('label');
        checkWrap.className = 'bool-toggle';
        const check = document.createElement('input');
        check.type = 'checkbox';
        check.checked = String(field.value || '').toLowerCase() === 'true';
        const t = document.createElement('span');
        t.textContent = check.checked ? 'Enabled' : 'Disabled';
        check.addEventListener('change', () => {
          rememberUndoSnapshot();
          field.value = check.checked ? 'true' : 'false';
          t.textContent = check.checked ? 'Enabled' : 'Disabled';
          setDirty(true);
        });
        checkWrap.appendChild(check);
        checkWrap.appendChild(t);
        controlWrap.appendChild(checkWrap);
        enableBooleanRowToggle(row, check);
      } else if (desiredControl === 'number' || (parseIntFromDisplayValue(field.value) != null && !/[A-Za-z]/.test(String(field.value || '').replace(/\(-?\d+\)\s*$/, '')))) {
        const num = document.createElement('input');
        num.type = 'number';
        if (Number.isFinite(spec.min)) num.min = String(spec.min);
        if (Number.isFinite(spec.max)) num.max = String(spec.max);
        const n = parseIntFromDisplayValue(field.value);
        num.value = n == null ? '' : String(n);
        wireGroupedUndoSession(num, {
          key: `RULE_FIELD:${tabKey}:${selectedBaseIndex}:${baseKey}`,
          getValue: () => num.value
        });
        num.addEventListener('input', () => {
          field.value = num.value;
          setDirty(true);
        });
        controlWrap.appendChild(num);
      } else {
        const input = document.createElement('input');
        input.type = 'text';
        input.value = String(field.value || '');
        wireGroupedUndoSession(input, {
          key: `RULE_FIELD:${tabKey}:${selectedBaseIndex}:${baseKey}`,
          getValue: () => input.value
        });
        input.addEventListener('input', () => {
          field.value = input.value;
          setDirty(true);
        });
        controlWrap.appendChild(input);
      }
    } else {
      const hasEnumOptions = enumOptions.length > 0;
      const hasRefOptions = refOptions.length > 0;
      const useReferencePicker = hasRefOptions && (desiredControl === 'reference' || (!desiredControl && !hasEnumOptions));
      if (useResourceTypeSegmented) {
        const parsedCurrent = parseIntFromDisplayValue(field.value);
        const current = enumOptions.find((opt) => String(opt.value) === String(parsedCurrent == null ? field.value : parsedCurrent));
        const segmented = makeSegmentedChoiceControl(
          enumOptions.map((opt) => String(opt.label || opt.value || '')),
          current ? String(current.label || current.value || '') : '',
          null,
          { disabled: true }
        );
        controlWrap.appendChild(segmented);
      } else if (useReferencePicker) {
        const labelText = String(field.label || field.key || 'value').trim();
        const isTechPrereqField = tabKey === 'technologies' && /^prerequisite/i.test(String(field.baseKey || field.key || ''));
        const normalizedCurrentValue = isTechPrereqField
          ? (() => {
              const idx = resolveTechIndexFromValue(field.value);
              return idx == null ? '-1' : String(idx);
            })()
          : field.value;
        const picker = createReferencePicker({
          options: refOptions,
          targetTabKey: (BIQ_FIELD_REFS[tabKey] || {})[normalizeRuleLookupKey(field && (field.baseKey || field.key))] || '',
          currentValue: normalizedCurrentValue,
          searchPlaceholder: `Search ${labelText}...`,
          noneLabel: '(none)',
          showOptionThumbs: true,
          readOnly: true
        });
        controlWrap.appendChild(picker);
      } else {
        const text = document.createElement('div');
        text.className = 'field-meta';
        text.textContent = formatFieldValueForDisplay(tabKey, field);
        controlWrap.appendChild(text);
      }
    }
    row.appendChild(controlWrap);
    groupCard.appendChild(row);
  });
}

function isRuleFieldChecked(field) {
  const raw = String(field && field.value || '').trim().toLowerCase();
  return raw === 'true' || raw === '1';
}

function createRuleFieldTooltipText(entry, tabKey, field) {
  const ruleFieldKey = String(field && (field.baseKey || field.key) || '');
  return withFieldHelp(
    `${formatSourceInfo(entry && entry.sourceMeta && entry.sourceMeta.biq, 'BIQ')}\nField: ${ruleFieldKey}`,
    { tabKey, fieldKey: ruleFieldKey }
  );
}

function createImprovementCompactRow(entry, labelText) {
  const row = document.createElement('div');
  row.className = 'rule-row improvement-compact-row';
  const label = document.createElement('label');
  label.className = 'field-meta';
  label.textContent = labelText;
  row.appendChild(label);
  const controlWrap = document.createElement('div');
  controlWrap.className = 'rule-control improvement-compact-control';
  row.appendChild(controlWrap);
  return { row, label, controlWrap };
}

function buildImprovementBoolChip(field, chipLabel, editable) {
  if (!field) return null;
  if (editable) {
    const toggle = document.createElement('label');
    toggle.className = 'bool-toggle';
    const check = document.createElement('input');
    check.type = 'checkbox';
    check.checked = isRuleFieldChecked(field);
    const text = document.createElement('span');
    text.textContent = chipLabel;
    check.addEventListener('change', () => {
      rememberUndoSnapshot();
      field.value = check.checked ? 'true' : 'false';
      setDirty(true);
    });
    toggle.appendChild(check);
    toggle.appendChild(text);
    return toggle;
  }
  const chip = document.createElement('span');
  chip.className = 'key-display-chip';
  chip.textContent = isRuleFieldChecked(field) ? chipLabel : `${chipLabel}: Off`;
  return chip;
}

function buildImprovementNumberPill(field, pillLabel, editable, min = null) {
  if (!field) return null;
  const wrap = document.createElement('div');
  wrap.className = 'improvement-number-pill';
  const title = document.createElement('span');
  title.className = 'field-meta';
  title.textContent = pillLabel;
  wrap.appendChild(title);
  if (editable) {
    const input = document.createElement('input');
    input.type = 'number';
    if (Number.isFinite(min)) input.min = String(min);
    const n = parseIntFromDisplayValue(field.value);
    input.value = n == null ? '' : String(n);
    wireGroupedUndoSession(input, {
      key: `IMPROVEMENT_PILL:${normalizeRuleLookupKey(field && (field.baseKey || field.key))}`,
      getValue: () => input.value
    });
    input.addEventListener('input', () => {
      field.value = input.value;
      setDirty(true);
    });
    wrap.appendChild(input);
  } else {
    const value = document.createElement('span');
    value.className = 'key-display-chip';
    value.textContent = String(parseIntFromDisplayValue(field.value) ?? 0);
    wrap.appendChild(value);
  }
  return wrap;
}

const IMPROVEMENT_TOP_FIELD_KEYS = new Set([
  'civilopediaentry',
  'wonder',
  'smallwonder',
  'improvement',
  'reqadvance',
  'obsoleteby',
  'reqgovernment',
  'reqimprovement',
  'reqresource1',
  'reqresource2'
]);

function getImprovementTopFieldValue(field, fallback = '(none)') {
  const raw = String(field && field.value || '').trim();
  if (!raw || raw === '-1' || /^none$/i.test(raw)) return fallback;
  return raw;
}

function createImprovementTopRow(entry, labelText, sourceFields = []) {
  const row = document.createElement('div');
  row.className = 'identity-key-row improvement-top-row';
  const label = document.createElement('label');
  label.className = 'field-meta identity-key-label';
  const strong = document.createElement('strong');
  strong.textContent = labelText;
  label.appendChild(strong);
  sourceFields.filter(Boolean).forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
  row.appendChild(label);
  const control = document.createElement('div');
  control.className = 'identity-key-control improvement-top-control';
  row.appendChild(control);
  return { row, label, control };
}

function buildImprovementTopReferenceControl(field, labelText, referenceEditable) {
  const options = getReferenceOptionsForField('improvements', field);
  if (options.length > 0) {
    const normalizedCurrentValue = field.value;
    return createReferencePicker({
      options,
      targetTabKey: (BIQ_FIELD_REFS.improvements || {})[normalizeRuleLookupKey(field && (field.baseKey || field.key))] || '',
      currentValue: normalizedCurrentValue,
      searchPlaceholder: `Search ${labelText || String(field.label || field.key || 'value')}...`,
      noneLabel: '(none)',
      showOptionThumbs: true,
      readOnly: !referenceEditable,
      onSelect: referenceEditable ? (value) => {
        rememberUndoSnapshot();
        field.value = String(value);
        setDirty(true);
      } : null
    });
  }
  const text = document.createElement('span');
  text.className = 'key-display-chip';
  text.textContent = getImprovementTopFieldValue(field);
  return text;
}

function renderImprovementTopControls(entry, identityGrid, referenceEditable) {
  if (!entry || !identityGrid) return;

  const topReferenceRows = [
    ['Required Technology', getBiqFieldByBaseKey(entry, 'reqadvance')],
    ['Made obsolete by', getBiqFieldByBaseKey(entry, 'obsoleteby')],
    ['Required Government', getBiqFieldByBaseKey(entry, 'reqgovernment')],
    ['Required Improvement', getBiqFieldByBaseKey(entry, 'reqimprovement')]
  ];
  topReferenceRows.forEach(([labelText, field]) => {
    if (!field) return;
    const { row, control } = createImprovementTopRow(entry, labelText, [field]);
    control.appendChild(buildImprovementTopReferenceControl(field, labelText, referenceEditable));
    identityGrid.appendChild(row);
  });
}

function appendImprovementSpecialRows(groupCard, groupName, fields, entry, referenceEditable) {
  const consumed = new Set();
  if (groupName === 'Properties') {
    // Category is intentionally rendered under Requirements so it sits with the
    // rest of the prerequisite/setup controls.
  } else if (groupName === 'Military') {
    const veteranFields = [
      { field: getRuleFieldByBaseKey(fields, 'veteranairunits'), label: 'Air' },
      { field: getRuleFieldByBaseKey(fields, 'veteranunits'), label: 'Land' },
      { field: getRuleFieldByBaseKey(fields, 'veteranseaunits'), label: 'Sea' }
    ].filter((item) => item.field);
    if (veteranFields.length > 0) {
      veteranFields.forEach((item) => consumed.add(item.field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Veteran Units');
      veteranFields.forEach((item) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', item.field)));
      veteranFields.forEach((item) => {
        controlWrap.appendChild(buildImprovementBoolChip(item.field, item.label, referenceEditable));
      });
      groupCard.appendChild(row);
    }
  } else if (groupName === 'Requirements') {
    const resourceField1 = getRuleFieldByBaseKey(fields, 'reqresource1');
    const resourceField2 = getRuleFieldByBaseKey(fields, 'reqresource2');
    const resourceFields = [resourceField1, resourceField2].filter(Boolean);
    const radiusField = getRuleFieldByBaseKey(fields, 'goodsmustbeincityradius');
    if (resourceFields.length > 0 || radiusField) {
      resourceFields.forEach((field) => consumed.add(field));
      if (radiusField) consumed.add(radiusField);
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Required Resources');
      [...resourceFields, radiusField].filter(Boolean).forEach((field) => {
        attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field));
      });
      controlWrap.classList.add('improvement-resource-array');
      const normalizedValues = resourceFields.map((field) => {
        const raw = String(field && field.value || '').trim();
        return (!raw || raw === '-1' || /^none$/i.test(raw)) ? '' : raw;
      });
      let visibleCount = 1;
      if (normalizedValues[0]) visibleCount = Math.min(resourceFields.length, 2);
      resourceFields.slice(0, visibleCount).forEach((field, idx) => {
        const cell = document.createElement('div');
        cell.className = 'improvement-resource-array-item';
        const cellLabel = document.createElement('div');
        cellLabel.className = 'field-meta';
        cellLabel.textContent = `[${idx}]`;
        cell.appendChild(cellLabel);
        const picker = createReferencePicker({
          options: getReferenceOptionsForField('improvements', field),
          targetTabKey: (BIQ_FIELD_REFS.improvements || {})[normalizeRuleLookupKey(field && (field.baseKey || field.key))] || '',
          currentValue: field.value,
          searchPlaceholder: `Search ${String(field.label || field.key || 'resource')}...`,
          noneLabel: '(none)',
          showOptionThumbs: true,
          readOnly: !referenceEditable,
          onSelect: referenceEditable ? (value) => {
            rememberUndoSnapshot();
            field.value = String(value);
            setDirty(true);
            renderActiveTab({ preserveTabScroll: true });
          } : null
        });
        cell.appendChild(picker);
        controlWrap.appendChild(cell);
      });
      if (radiusField) controlWrap.appendChild(buildImprovementBoolChip(radiusField, 'In city radius', referenceEditable));
      groupCard.appendChild(row);
    }
    const wonder = getRuleFieldByBaseKey(fields, 'wonder');
    const smallWonder = getRuleFieldByBaseKey(fields, 'smallwonder');
    const improvement = getRuleFieldByBaseKey(fields, 'improvement');
    const categoryFields = [wonder, smallWonder, improvement].filter(Boolean);
    if (categoryFields.length > 0) {
      categoryFields.forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Category');
      categoryFields.forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      const options = [
        { field: wonder, label: 'Wonder' },
        { field: smallWonder, label: 'Small Wonder' },
        { field: improvement, label: 'Improvement' }
      ].filter((item) => item.field);
      const current = options.find((item) => isRuleFieldChecked(item.field)) || options[0] || null;
      const segmented = makeSegmentedChoiceControl(
        options.map((item) => item.label),
        current ? current.label : '',
        referenceEditable ? (nextLabel) => {
          const selected = options.find((item) => item.label === nextLabel);
          if (!selected) return;
          rememberUndoSnapshot();
          options.forEach((opt) => {
            opt.field.value = opt.field === selected.field ? 'true' : 'false';
          });
          setDirty(true);
        } : null,
        { disabled: !referenceEditable }
      );
      controlWrap.appendChild(segmented);
      groupCard.appendChild(row);
    }
  } else if (groupName === 'Trade') {
    const cityField = getRuleFieldByBaseKey(fields, 'reducescorruption');
    const empireField = getRuleFieldByBaseKey(fields, 'forbiddenpalace');
    const pair = [cityField, empireField].filter(Boolean);
    if (pair.length > 0) {
      pair.forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Reduces Corruption');
      pair.forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      if (cityField) controlWrap.appendChild(buildImprovementBoolChip(cityField, 'City', referenceEditable));
      if (empireField) controlWrap.appendChild(buildImprovementBoolChip(empireField, 'Empire', referenceEditable));
      groupCard.appendChild(row);
    }
  } else if (groupName === 'Happiness') {
    const happy = getRuleFieldByBaseKey(fields, 'happy');
    const happyAll = getRuleFieldByBaseKey(fields, 'happyall');
    const unhappy = getRuleFieldByBaseKey(fields, 'unhappy');
    const unhappyAll = getRuleFieldByBaseKey(fields, 'unhappyall');
    const warCity = getRuleFieldByBaseKey(fields, 'reduceswarweariness');
    const warEmpire = getRuleFieldByBaseKey(fields, 'reducewarweariness') || getRuleFieldByBaseKey(fields, 'empirereduceswarweariness');
    const warEmpireAlias = getRuleFieldByBaseKey(fields, 'empirereduceswarweariness');
    if (happy || happyAll) {
      [happy, happyAll].filter(Boolean).forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Happy Faces');
      [happy, happyAll].filter(Boolean).forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      if (happy) controlWrap.appendChild(buildImprovementNumberPill(happy, 'City', referenceEditable, 0));
      if (happyAll) controlWrap.appendChild(buildImprovementNumberPill(happyAll, 'Global', referenceEditable, 0));
      groupCard.appendChild(row);
    }
    if (unhappy || unhappyAll) {
      [unhappy, unhappyAll].filter(Boolean).forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Unhappy Faces');
      [unhappy, unhappyAll].filter(Boolean).forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      if (unhappy) controlWrap.appendChild(buildImprovementNumberPill(unhappy, 'City', referenceEditable, 0));
      if (unhappyAll) controlWrap.appendChild(buildImprovementNumberPill(unhappyAll, 'Global', referenceEditable, 0));
      groupCard.appendChild(row);
    }
    if (warCity || warEmpire) {
      [warCity, warEmpire, warEmpireAlias].filter(Boolean).forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Reduces War Weariness');
      [warCity, warEmpire].filter(Boolean).forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      if (warCity) controlWrap.appendChild(buildImprovementBoolChip(warCity, 'City', referenceEditable));
      if (warEmpire) controlWrap.appendChild(buildImprovementBoolChip(warEmpire, 'Empire', referenceEditable));
      groupCard.appendChild(row);
    }
  } else if (groupName === 'Food') {
    const level2 = getRuleFieldByBaseKey(fields, 'allowcitylevel2');
    const level3 = getRuleFieldByBaseKey(fields, 'allowcitylevel3');
    const pair = [level2, level3].filter(Boolean);
    if (pair.length > 0) {
      pair.forEach((field) => consumed.add(field));
      const { row, label, controlWrap } = createImprovementCompactRow(entry, 'Allows City Size');
      pair.forEach((field) => attachRichTooltip(label, createRuleFieldTooltipText(entry, 'improvements', field)));
      if (level2) controlWrap.appendChild(buildImprovementBoolChip(level2, '2', referenceEditable));
      if (level3) controlWrap.appendChild(buildImprovementBoolChip(level3, '3', referenceEditable));
      groupCard.appendChild(row);
    }
  }
  return consumed;
}

function canonicalBiqFieldKey(field) {
  return String(field && (field.baseKey || field.key) || '').toLowerCase().replace(/[^a-z0-9]/g, '');
}

function collapseUnitRuleFields(fields) {
  const out = [];
  const seen = new Set();
  const multiBuckets = new Map();
  (Array.isArray(fields) ? fields : []).forEach((field) => {
    const canon = canonicalBiqFieldKey(field);
    if (!canon) return;
    if (UNIT_MULTI_VALUE_FIELD_KEYS.has(canon)) {
      let bucket = multiBuckets.get(canon);
      if (!bucket) {
        bucket = { first: field, values: [] };
        multiBuckets.set(canon, bucket);
        out.push(bucket);
      }
      const value = String(field && field.value || '').trim();
      if (value) bucket.values.push(value);
      return;
    }
    if (seen.has(canon)) return;
    seen.add(canon);
    out.push(field);
  });
  return out.map((item) => {
    if (!item || !item.first) return item;
    return {
      ...item.first,
      value: item.values.join(', '),
      multiValues: item.values
    };
  });
}

function setUnitListFieldValues(entry, key, values) {
  if (!entry || !Array.isArray(entry.biqFields)) return;
  const targetKey = String(key || '').trim();
  const targetCanon = targetKey.toLowerCase().replace(/[^a-z0-9]/g, '');
  const cleaned = (Array.isArray(values) ? values : []).map((v) => String(v || '').trim()).filter(Boolean);
  const removedFields = [];
  let insertAt = -1;
  const kept = [];
  entry.biqFields.forEach((field) => {
    const canon = canonicalBiqFieldKey(field);
    if (canon === targetCanon) {
      removedFields.push(field);
      if (insertAt < 0) insertAt = kept.length;
      return;
    }
    kept.push(field);
  });
  if (insertAt < 0) insertAt = kept.length;
  const template = removedFields[0] || { baseKey: targetKey, key: targetKey, label: toFriendlyKey(targetKey) };
  const preservedCount = Math.max(cleaned.length, removedFields.length);
  const nextFields = Array.from({ length: preservedCount }, (_, idx) => {
    const prior = removedFields[idx] || template;
    const value = idx < cleaned.length ? cleaned[idx] : '';
    return {
      ...prior,
      value,
      originalValue: String(prior && prior.originalValue || '')
    };
  });
  kept.splice(insertAt, 0, ...nextFields);
  entry.biqFields = kept;
  if (targetCanon === 'stealthtarget') {
    const countField = entry.biqFields.find((field) => canonicalBiqFieldKey(field) === 'numstealthtargets');
    if (countField) countField.value = String(cleaned.length);
  }
  if (targetCanon === 'legalunittelepad') {
    const countField = entry.biqFields.find((field) => canonicalBiqFieldKey(field) === 'numlegalunittelepads');
    if (countField) countField.value = String(cleaned.length);
  }
  if (targetCanon === 'legalbuildingtelepad') {
    const countField = entry.biqFields.find((field) => canonicalBiqFieldKey(field) === 'numlegalbuildingtelepads');
    if (countField) countField.value = String(cleaned.length);
  }
}

function getUnitListFieldState(entry, candidateKeys, fallbackKey) {
  const aliases = (Array.isArray(candidateKeys) ? candidateKeys : []).map((k) => String(k || '').trim()).filter(Boolean);
  const wanted = aliases.map((k) => k.toLowerCase().replace(/[^a-z0-9]/g, ''));
  let selectedKey = '';
  const values = [];
  const fields = Array.isArray(entry && entry.biqFields) ? entry.biqFields : [];
  fields.forEach((field) => {
    const rawKey = String(field && (field.baseKey || field.key) || '').trim();
    const canon = rawKey.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (!canon || !wanted.includes(canon)) return;
    if (!selectedKey) selectedKey = rawKey;
    const value = String(field && field.value || '').trim();
    if (value) values.push(value);
  });
  return {
    key: selectedKey || String(fallbackKey || aliases[0] || '').trim(),
    values
  };
}

function getTerrainFlagRowsForUnits() {
  const terrainTab = state.bundle && state.bundle.tabs && state.bundle.tabs.terrain;
  const terrainSection = terrainTab && Array.isArray(terrainTab.sections)
    ? terrainTab.sections.find((section) => String(section && section.code || '').toUpperCase() === 'TERR')
    : null;
  const records = terrainSection && Array.isArray(terrainSection.records) ? terrainSection.records : [];
  return records.map((record, idx) => {
    const pediaEntry = getTerrainCivilopediaEntryForRecord(terrainTab, 'TERR', record);
    const label = String(record && record.name || (pediaEntry && pediaEntry.name) || `Terrain ${idx + 1}`).trim();
    return {
      index: idx,
      label: label || `Terrain ${idx + 1}`,
      entry: pediaEntry || null
    };
  });
}

function renderTerrainFlagEditor(entry, values, onValuesChange) {
  const wrap = document.createElement('div');
  wrap.className = 'terrain-flag-editor';
  const rows = getTerrainFlagRowsForUnits();
  if (rows.length === 0) {
    const hint = document.createElement('div');
    hint.className = 'field-meta';
    hint.textContent = '(No terrain data found)';
    wrap.appendChild(hint);
    return wrap;
  }
  const initialValues = Array.from({ length: Math.max(rows.length, Array.isArray(values) ? values.length : 0) }, (_, idx) => String((Array.isArray(values) && values[idx] != null) ? values[idx] : '0'));
  rows.forEach((row, idx) => {
    const line = document.createElement('label');
    line.className = 'terrain-flag-row';
    line.style.display = 'grid';
    line.style.gridTemplateColumns = '28px 1fr auto';
    line.style.alignItems = 'center';
    line.style.gap = '10px';
    line.style.cursor = 'pointer';

    const thumb = document.createElement('span');
    thumb.className = 'entry-thumb terrain-flag-thumb';
    if (row.entry) loadReferenceListThumbnail('terrainPedia', row.entry, thumb);
    line.appendChild(thumb);

    const text = document.createElement('span');
    text.textContent = row.label;
    line.appendChild(text);

    const check = document.createElement('input');
    check.type = 'checkbox';
    check.checked = String(initialValues[idx] || '').trim() === '1' || String(initialValues[idx] || '').trim().toLowerCase() === 'true';
    check.style.accentColor = '#1aa79c';
    check.style.cursor = 'pointer';
    check.addEventListener('change', () => {
      const currentState = getUnitListFieldState(entry, ['ignore_movement_cost', 'ignoremovementcost'], 'ignore_movement_cost');
      const updated = Array.from({ length: Math.max(rows.length, Array.isArray(currentState.values) ? currentState.values.length : 0) }, (_, valueIdx) => String((Array.isArray(currentState.values) && currentState.values[valueIdx] != null) ? currentState.values[valueIdx] : '0'));
      updated[idx] = check.checked ? '1' : '0';
      if (typeof onValuesChange === 'function') onValuesChange(updated);
    });
    line.appendChild(check);
    wrap.appendChild(line);
  });
  return wrap;
}

function getCivilizationNoteListState(entry, countKey, itemPrefix = 'note') {
  const fields = Array.isArray(entry && entry.biqFields) ? entry.biqFields : [];
  const targetCount = String(countKey || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  const targetItem = String(itemPrefix || 'note').toLowerCase().replace(/[^a-z0-9]/g, '');
  let countIndex = -1;
  for (let i = 0; i < fields.length; i += 1) {
    if (canonicalBiqFieldKey(fields[i]) === targetCount) {
      countIndex = i;
      break;
    }
  }
  if (countIndex < 0) {
    return {
      countIndex: -1,
      notesStart: -1,
      notesEnd: -1,
      values: []
    };
  }
  const isItemField = (field) => {
    const canon = canonicalBiqFieldKey(field);
    return canon === targetItem || new RegExp(`^${targetItem}\\d+$`).test(canon);
  };
  let notesStart = countIndex + 1;
  while (notesStart < fields.length && !isItemField(fields[notesStart])) notesStart += 1;
  if (notesStart >= fields.length) {
    return {
      countIndex,
      notesStart,
      notesEnd: notesStart,
      values: []
    };
  }
  let notesEnd = notesStart;
  while (notesEnd < fields.length && isItemField(fields[notesEnd])) notesEnd += 1;
  const values = fields.slice(notesStart, notesEnd)
    .map((field) => String(field && field.value || '').trim())
    .filter(Boolean);
  return { countIndex, notesStart, notesEnd, values };
}

function setCivilizationNoteListValues(entry, countKey, values, itemPrefix = 'note') {
  if (!entry) return;
  if (!Array.isArray(entry.biqFields)) entry.biqFields = [];
  const fields = entry.biqFields;
  const targetCount = String(countKey || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  const targetItem = String(itemPrefix || 'note').toLowerCase().replace(/[^a-z0-9]/g, '');
  let countField = fields.find((field) => canonicalBiqFieldKey(field) === targetCount);
  if (!countField) {
    countField = ensureBiqFieldByBaseKey(entry, countKey, toFriendlyKey(countKey), '0');
  }
  const state = getCivilizationNoteListState(entry, countKey, itemPrefix);
  const cleaned = (Array.isArray(values) ? values : [])
    .map((value) => String(value || '').trim())
    .filter(Boolean);
  const start = state.notesStart < 0 ? Math.max(0, fields.indexOf(countField) + 1) : state.notesStart;
  const end = state.notesEnd < 0 ? start : state.notesEnd;
  const existingNotes = (start >= 0 && end > start) ? fields.slice(start, end) : [];
  const template = existingNotes[0] || {
    key: targetItem,
    baseKey: targetItem,
    label: cfgLabelFromPrefix(targetItem),
    editable: true
  };
  const nextNotes = cleaned.map((value, idx) => ({
    ...template,
    key: itemPrefix === 'note' ? 'note' : `${targetItem}_${idx}`,
    baseKey: itemPrefix === 'note' ? 'note' : `${targetItem}_${idx}`,
    label: existingNotes[idx] ? String(existingNotes[idx].label || existingNotes[idx].key || template.label) : template.label,
    value
  }));
  fields.splice(start, Math.max(0, end - start), ...nextNotes);
  countField.value = String(cleaned.length);
}

function getTerrainResourceOptions() {
  const tab = state.bundle && state.bundle.tabs && state.bundle.tabs.resources;
  const entries = tab && Array.isArray(tab.entries) ? tab.entries : [];
  return entries
    .map((entry, idx) => ({
      value: String(Number.isFinite(entry && entry.biqIndex) ? entry.biqIndex : idx),
      label: String(entry && (entry.name || entry.civilopediaKey) || `Resource ${idx + 1}`),
      entry: entry || null
    }))
    .sort((a, b) => Number.parseInt(a.value, 10) - Number.parseInt(b.value, 10));
}

function parseTerrainMaskCsv(raw) {
  return String(raw || '')
    .split(/[,\s]+/)
    .map((part) => String(part || '').trim())
    .filter(Boolean)
    .map((part) => {
      const n = Number.parseInt(part, 10);
      return Number.isFinite(n) && n !== 0 ? 1 : 0;
    });
}

function deriveTerrainMaskFromNotes(record) {
  const fields = Array.isArray(record && record.fields) ? record.fields : [];
  const countField = fields.find((field) => canonicalBiqFieldKey(field) === 'numpossibleresources');
  const declaredCount = Math.max(0, parseIntFromDisplayValue(countField && countField.value) || 0);
  const countIndex = countField ? fields.indexOf(countField) : -1;
  if (countIndex < 0) return [];
  let i = countIndex + 1;
  const mask = [];
  while (i < fields.length && canonicalBiqFieldKey(fields[i]) === 'note') {
    const v = Number.parseInt(String(fields[i] && fields[i].value || '').trim(), 10);
    mask.push(Number.isFinite(v) && v !== 0 ? 1 : 0);
    i += 1;
  }
  if (declaredCount > mask.length) {
    while (mask.length < declaredCount) mask.push(0);
  }
  return mask;
}

function getTerrainResourceMask(record) {
  if (!record || !Array.isArray(record.fields)) return [];
  const maskField = record.fields.find((field) => canonicalBiqFieldKey(field) === 'possibleresourcesmask');
  if (maskField && String(maskField.value || '').trim()) {
    return parseTerrainMaskCsv(maskField.value);
  }
  return deriveTerrainMaskFromNotes(record);
}

function ensureTerrainResourceMaskField(record) {
  if (!record) return null;
  if (!Array.isArray(record.fields)) record.fields = [];
  const existing = record.fields.find((field) => canonicalBiqFieldKey(field) === 'possibleresourcesmask');
  if (existing) return existing;
  const initial = getTerrainResourceMask(record);
  const csv = initial.join(',');
  const created = {
    key: 'possible_resources_mask',
    baseKey: 'possible_resources_mask',
    label: 'Possible Resources Mask',
    value: csv,
    originalValue: csv,
    editable: true
  };
  record.fields.push(created);
  return created;
}

function cfgLabelFromPrefix(prefix) {
  const normalized = String(prefix || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  if (normalized === 'note') return 'Note';
  if (normalized === 'cityname') return 'City Name';
  if (normalized === 'milleader') return 'Military Leader';
  if (normalized === 'scientificleader') return 'Scientific Leader';
  return toFriendlyKey(prefix);
}

function renderCivilizationNoteListEditor(entry, cfg, referenceEditable) {
  const wrap = document.createElement('div');
  wrap.className = 'civilization-name-list-editor';
  const itemPrefix = String(cfg && cfg.itemPrefix || 'note');
  const state = getCivilizationNoteListState(entry, cfg.countKey, itemPrefix);
  if (!referenceEditable) {
    const text = document.createElement('div');
    text.className = 'field-meta civilization-name-list-readonly';
    text.textContent = state.values.length ? state.values.join(', ') : '(none)';
    wrap.appendChild(text);
    return wrap;
  }

  let items = state.values.slice();
  const toolbar = document.createElement('div');
  toolbar.className = 'civilization-name-list-toolbar';
  const title = document.createElement('div');
  title.className = 'civilization-name-list-toolbar-title';
  title.textContent = String(cfg && cfg.label || 'List');
  toolbar.appendChild(title);
  const count = document.createElement('span');
  count.className = 'civilization-name-list-count';
  toolbar.appendChild(count);

  const addRow = document.createElement('div');
  addRow.className = 'civilization-name-list-add';
  const addInput = document.createElement('input');
  addInput.type = 'search';
  addInput.placeholder = cfg.placeholder;
  addInput.className = 'civilization-name-list-input app-search-input';
  const addBtn = document.createElement('button');
  addBtn.type = 'button';
  addBtn.className = 'civilization-name-list-add-btn';
  addBtn.textContent = '+';
  addBtn.title = `Add ${cfg.label}`;
  addRow.appendChild(addInput);
  addRow.appendChild(addBtn);

  const list = document.createElement('div');
  list.className = 'civilization-name-list-items';

  const commit = () => {
    setCivilizationNoteListValues(entry, cfg.countKey, items, itemPrefix);
    setDirty(true);
  };

  const rerender = () => {
    count.textContent = `${items.length} ${items.length === 1 ? 'entry' : 'entries'}`;
    list.innerHTML = '';
    if (items.length === 0) {
      const empty = document.createElement('div');
      empty.className = 'field-meta civilization-name-list-empty';
      empty.textContent = '(none)';
      list.appendChild(empty);
    } else {
      items.forEach((value, idx) => {
        const line = document.createElement('div');
        line.className = 'civilization-name-list-item';
        const index = document.createElement('span');
        index.className = 'civilization-name-list-index';
        index.textContent = String(idx + 1);
        const input = document.createElement('input');
        input.type = 'text';
        input.placeholder = cfg.placeholder;
        input.value = value;
        input.className = 'civilization-name-list-input';
        wireGroupedUndoSession(input, {
          key: `CIV_NOTE:${String(cfg.countKey || '')}:${idx}`,
          getValue: () => input.value
        });
        input.addEventListener('input', () => {
          items[idx] = input.value;
          commit();
        });
        const del = document.createElement('button');
        del.type = 'button';
        del.className = 'civilization-name-list-remove-btn';
        withRemoveIcon(del, '');
        del.title = `Remove ${cfg.label} ${idx + 1}`;
        del.addEventListener('click', () => {
          rememberUndoSnapshot();
          items.splice(idx, 1);
          commit();
          rerender();
        });
        line.appendChild(index);
        line.appendChild(input);
        line.appendChild(del);
        list.appendChild(line);
      });
    }
  };

  const addItem = () => {
    const value = String(addInput.value || '').trim();
    if (!value) return;
    rememberUndoSnapshot();
    items.push(value);
    addInput.value = '';
    commit();
    rerender();
    const lastInput = list.querySelector('.kv-row.compact input:last-of-type');
    if (lastInput) lastInput.focus({ preventScroll: true });
  };
  const syncAddButton = () => {
    const enabled = String(addInput.value || '').trim().length > 0;
    addBtn.disabled = !enabled;
    addBtn.setAttribute('aria-disabled', enabled ? 'false' : 'true');
  };
  addBtn.addEventListener('click', addItem);
  addInput.addEventListener('input', syncAddButton);
  addInput.addEventListener('keydown', (ev) => {
    if (ev.key === 'Escape') {
      ev.preventDefault();
      if (addInput.value) {
        addInput.value = '';
        syncAddButton();
      }
      return;
    }
    if (ev.key !== 'Enter') return;
    ev.preventDefault();
    addItem();
  });
  wrap.appendChild(toolbar);
  wrap.appendChild(addRow);
  wrap.appendChild(list);
  syncAddButton();
  rerender();
  return wrap;
}

function setUnitAbilitySelections(entry, selectedValues) {
  if (!entry || !Array.isArray(entry.biqFields)) return;
  const wanted = new Set((Array.isArray(selectedValues) ? selectedValues : []).map((v) => String(v || '').trim().toLowerCase()).filter(Boolean));
  UNIT_ABILITY_OPTION_KEYS.forEach((key) => {
    const field = entry.biqFields.find((f) => canonicalBiqFieldKey(f) === key);
    if (!field) return;
    field.value = wanted.has(key) ? 'true' : 'false';
  });
}

function getUnitAbilitySelections(entry) {
  const out = [];
  const fields = Array.isArray(entry && entry.biqFields) ? entry.biqFields : [];
  UNIT_ABILITY_OPTION_KEYS.forEach((key) => {
    const field = fields.find((f) => canonicalBiqFieldKey(f) === key);
    const on = String(field && field.value || '').trim().toLowerCase() === 'true';
    if (on) out.push(key);
  });
  return out;
}

function parseSigned32FromValue(value) {
  const n = parseIntFromDisplayValue(value);
  if (n == null) return 0;
  return n | 0;
}

function toSigned32StringFromUnsigned(unsigned32) {
  const u = Number(unsigned32) >>> 0;
  return u > 0x7fffffff ? String(u - 0x100000000) : String(u);
}

function decodeAvailableToIndices(rawValue) {
  const mask = parseSigned32FromValue(rawValue) >>> 0;
  const out = [];
  for (let i = 0; i < 32; i++) {
    if (((mask >>> i) & 1) === 1) out.push(i);
  }
  return out;
}

function encodeAvailableToFromIndices(indices) {
  let mask = 0 >>> 0;
  (Array.isArray(indices) ? indices : []).forEach((idx) => {
    const i = Number.parseInt(String(idx), 10);
    if (!Number.isFinite(i) || i < 0 || i > 31) return;
    mask = (mask | ((1 << i) >>> 0)) >>> 0;
  });
  return toSigned32StringFromUnsigned(mask);
}

function getCivilizationBitmaskOptions() {
  const tab = state.bundle && state.bundle.tabs && state.bundle.tabs.civilizations;
  const entries = tab && Array.isArray(tab.entries) ? tab.entries : [];
  return entries.map((entry, fallbackIdx) => {
    const idx = Number.isFinite(entry && entry.biqIndex) ? entry.biqIndex : fallbackIdx;
    return {
      value: String(idx),
      label: String(entry && entry.name || `Civilization ${idx}`),
      entry: entry || null
    };
  }).filter((opt) => Number.isFinite(Number.parseInt(opt.value, 10)) && Number.parseInt(opt.value, 10) >= 0 && Number.parseInt(opt.value, 10) < 32);
}

function isGovernmentRelationsField(field) {
  const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
  return /^performance_of_this_government_versus_government_\d+$/.test(base)
    || base === 'resistancemodifier'
    || base === 'briberymodifier';
}

function buildGovernmentRelationsRows(entry) {
  const fields = Array.isArray(entry && entry.biqFields) ? entry.biqFields : [];
  const rows = [];
  let current = null;
  fields.forEach((field) => {
    const base = String(field && (field.baseKey || field.key) || '').toLowerCase();
    const perfMatch = base.match(/^performance_of_this_government_versus_government_(\d+)$/);
    if (perfMatch) {
      const index = Number.parseInt(perfMatch[1], 10);
      const label = String(field && field.label || '').trim();
      const government = label.replace(/^Performance Vs\s*/i, '').trim() || `Government ${index + 1}`;
      current = { index, government, resistanceField: null, propagandaField: null };
      rows.push(current);
      return;
    }
    if (!current) return;
    if (base === 'resistancemodifier' && !current.resistanceField) {
      current.resistanceField = field;
      return;
    }
    if (base === 'briberymodifier' && !current.propagandaField) {
      current.propagandaField = field;
    }
  });
  return rows.sort((a, b) => a.index - b.index);
}

function renderGovernmentRelationsCard(entry, referenceEditable) {
  const rows = buildGovernmentRelationsRows(entry);
  if (rows.length === 0) return null;
  const card = document.createElement('div');
  card.className = 'rule-group-card';
  const title = document.createElement('div');
  title.className = 'rule-group-title';
  title.textContent = 'Government Relations Table';
  card.appendChild(title);

  const table = document.createElement('table');
  table.style.width = '100%';
  table.style.borderCollapse = 'collapse';
  table.style.fontSize = '12px';
  const thead = document.createElement('thead');
  const trh = document.createElement('tr');
  ['Government', 'Resistance Modifier', 'Propaganda'].forEach((h) => {
    const th = document.createElement('th');
    th.textContent = h;
    th.style.textAlign = 'left';
    th.style.padding = '6px 4px';
    th.style.borderBottom = '1px solid rgba(36, 25, 64, 0.2)';
    trh.appendChild(th);
  });
  thead.appendChild(trh);
  table.appendChild(thead);

  const tbody = document.createElement('tbody');
  rows.forEach((row) => {
    const tr = document.createElement('tr');
    const tdGov = document.createElement('td');
    tdGov.textContent = row.government;
    tdGov.style.padding = '6px 4px';
    const tdResistance = document.createElement('td');
    if (referenceEditable && row.resistanceField) {
      const input = document.createElement('input');
      input.type = 'number';
      const n = parseIntFromDisplayValue(row.resistanceField.value);
      input.value = n == null ? '' : String(n);
      wireGroupedUndoSession(input, {
        key: `GOV_REL_RESIST:${row.index}`,
        getValue: () => input.value
      });
      input.addEventListener('input', () => {
        row.resistanceField.value = input.value;
        setDirty(true);
      });
      tdResistance.appendChild(input);
    } else {
      tdResistance.textContent = formatFieldValueForDisplay('governments', row.resistanceField || { value: '' });
    }
    tdResistance.style.padding = '6px 4px';
    const tdProp = document.createElement('td');
    if (referenceEditable && row.propagandaField) {
      const input = document.createElement('input');
      input.type = 'number';
      const n = parseIntFromDisplayValue(row.propagandaField.value);
      input.value = n == null ? '' : String(n);
      wireGroupedUndoSession(input, {
        key: `GOV_REL_PROP:${row.index}`,
        getValue: () => input.value
      });
      input.addEventListener('input', () => {
        row.propagandaField.value = input.value;
        setDirty(true);
      });
      tdProp.appendChild(input);
    } else {
      tdProp.textContent = formatFieldValueForDisplay('governments', row.propagandaField || { value: '' });
    }
    tdProp.style.padding = '6px 4px';
    tr.appendChild(tdGov);
    tr.appendChild(tdResistance);
    tr.appendChild(tdProp);
    tbody.appendChild(tr);
  });
  table.appendChild(tbody);
  card.appendChild(table);
  return card;
}

