    if (cityCulture > 0) { levelX[0] += 5; levelX[1] += 6; levelX[2] += 4; levelX[3] += 2; levelX[4] += 4; levelX[5] += 2; levelX[6] += 2; levelX[7] += 2; levelX[8] += 4; levelX[9] += 2; levelX[10] += 4; levelX[11] += 6; levelX[12] += 5; }
